"""Jeen Language Model component for Langflow.

Exposes Jeen-configured LLMs as a standard Langflow ``LanguageModel`` so they
can be used by any downstream component that consumes language models (Agent,
Structured Output, Smart Transform, etc.). Inherits the two-output pattern
(Model Response / Language Model) from ``LCModelComponent``, mirroring the
stock Azure OpenAI component.

Endpoint:
  * Invocation: ``POST {LLM_CORE_URL}/api/v1/completions`` (user JWT)

Model selection is a refreshable dropdown populated from user-service's
``GET /api/v1/settings/me`` using the workspace JWT propagated by
``JeenJwtMiddleware``. The dropdown lists only the completion models the
flow author's organisation has enabled, mirroring the playground UI's
own model picker. The selected option is the canonical provider model
name (e.g. ``gpt-5.4-nano``) — forwarded verbatim through llm-core to
completion-service, exactly as it would be if typed by hand. Pre-existing
flows with a hardcoded ``model_name`` string keep working: the saved
value is preserved as a dropdown option even if the live list omits it.

FinOps attribution is automatic: `workflowId` and `workflowName` are read from
the running Langflow graph (`self.graph.flow_id`, `self.graph.flow_name`) and
forwarded under `context.dimensions` so completion-service can tag the
transaction with the originating workflow.
"""

from __future__ import annotations

import base64
import json
import os
import time
from typing import Any, Dict, List, Optional, Sequence
from uuid import uuid4

import requests

from langchain_core.callbacks import CallbackManagerForLLMRun
from langchain_core.language_models.chat_models import BaseChatModel
from langchain_core.messages import (
    AIMessage,
    AIMessageChunk,
    BaseMessage,
    HumanMessage,
    SystemMessage,
    ToolMessage,
)
from langchain_core.outputs import ChatGeneration, ChatGenerationChunk, ChatResult

from langflow.base.models.model import LCModelComponent
from langflow.field_typing import LanguageModel
from langflow.field_typing.range_spec import RangeSpec
from langflow.inputs import MessageTextInput, SliderInput
from langflow.io import (
    BoolInput,
    DropdownInput,
    IntInput,
    MultilineInput,
)


_DEFAULT_LLM_CORE_URL = os.getenv("JEEN_LLM_CORE_URL", "http://host.docker.internal:4010")
_DEFAULT_USER_SERVICE_URL = os.getenv("JEEN_USER_SERVICE_URL", "http://host.docker.internal:4001")
_REQUEST_TIMEOUT_SECONDS = float(os.getenv("JEEN_LANGUAGE_MODEL_TIMEOUT", "120"))
_STREAM_TIMEOUT_SECONDS = float(os.getenv("JEEN_LANGUAGE_MODEL_STREAM_TIMEOUT", "300"))
_AVAILABLE_MODELS_TIMEOUT_SECONDS = float(os.getenv("JEEN_LANGUAGE_MODEL_PICKER_TIMEOUT", "10"))


def _get_jeen_jwt() -> Optional[str]:
    """Read the workspace JWT propagated by JeenJwtMiddleware (lazy).

    Langflow rebuilds custom component instances by re-executing the
    component's source via ``Component(_code=...)``. That exec path
    drops module-level imports inside method scopes, so the import is
    deferred to call time. The middleware lives at ``/app/jeen_auth.py``
    on PYTHONPATH=/app inside the Jeen-flavoured Langflow image.
    """
    try:
        from jeen_auth import get_jeen_jwt as _impl
    except ImportError:
        return None
    try:
        return _impl()
    except Exception:  # noqa: BLE001
        return None


def _strip_bearer(token: str) -> str:
    """Normalise a token: trim whitespace, surrounding quotes, and any 'Bearer ' prefix."""
    cleaned = (token or "").strip()
    # Some upstream components wrap the JWT in quotes when serialising through a Message.
    if len(cleaned) >= 2 and cleaned[0] == cleaned[-1] and cleaned[0] in ("'", '"'):
        cleaned = cleaned[1:-1].strip()
    if cleaned.lower().startswith("bearer "):
        cleaned = cleaned[7:].strip()
    return cleaned


def _decode_jwt_payload(token: str) -> Optional[Dict[str, Any]]:
    """Best-effort base64url-decode of the JWT payload segment.

    Returns ``None`` if the value does not look like a JWT. Performs *no* signature
    verification — this is purely for client-side diagnostics so the component can
    detect obvious problems (expired token, wrong audience, not actually a JWT)
    before bothering llm-core.
    """
    if not token or token.count(".") != 2:
        return None
    payload_b64 = token.split(".", 2)[1]
    padding = "=" * (-len(payload_b64) % 4)
    try:
        raw = base64.urlsafe_b64decode(payload_b64 + padding)
        return json.loads(raw.decode("utf-8", errors="replace"))
    except (ValueError, json.JSONDecodeError):
        return None


def _summarize_jwt(token: str) -> str:
    """Produce a single-line summary of a JWT for log/error messages."""
    if not token:
        return "(empty)"
    if token.count(".") != 2:
        return f"(not a JWT - {len(token)} chars, {token.count('.')} dots)"
    payload = _decode_jwt_payload(token)
    if not isinstance(payload, dict):
        return f"(unparsable JWT - {len(token)} chars)"

    bits = []
    for key in ("userId", "sub", "aud", "iss"):
        val = payload.get(key)
        if val:
            bits.append(f"{key}={val}")
    exp = payload.get("exp")
    if isinstance(exp, (int, float)):
        now = int(time.time())
        remaining = int(exp) - now
        if remaining <= 0:
            bits.append(f"exp={exp} (EXPIRED {-remaining}s ago)")
        else:
            bits.append(f"exp={exp} ({remaining}s remaining)")
    return ", ".join(bits) if bits else "(JWT with no recognised claims)"


class JeenJwtError(ValueError):
    """Raised when the supplied access token is missing, malformed, or expired."""


def _validate_jwt(token: str) -> str:
    """Validate JWT shape + expiry client-side. Returns the cleaned token.

    Raises ``JeenJwtError`` with a precise, user-friendly message when the token
    is plainly bad (empty / non-JWT / expired). Signature/audience errors will
    still surface from llm-core; this just catches the cheap cases up front so
    the user gets a clear diagnostic instead of a generic 401.
    """
    cleaned = _strip_bearer(token)
    if not cleaned:
        raise JeenJwtError(
            "Access Token (JWT) is empty. Paste a token or connect a text output from an "
            "upstream component (e.g. jeen-attachments) into the Access Token field."
        )
    if cleaned.count(".") != 2:
        snippet = cleaned[:60] + ("..." if len(cleaned) > 60 else "")
        raise JeenJwtError(
            "Access Token does not look like a JWT (expected three '.'-separated segments). "
            f"Got: {snippet!r}. If you connected an upstream output, make sure it produces the "
            "raw token string and not a JSON payload."
        )
    payload = _decode_jwt_payload(cleaned)
    if isinstance(payload, dict):
        exp = payload.get("exp")
        if isinstance(exp, (int, float)) and int(exp) <= int(time.time()):
            raise JeenJwtError(
                "Access Token (JWT) is expired. Re-login to obtain a fresh token, then update "
                f"the Access Token field. Decoded: {_summarize_jwt(cleaned)}"
            )
    return cleaned


def _convert_messages_to_jeen(messages: Sequence[BaseMessage]) -> List[Dict[str, Any]]:
    """Map LangChain BaseMessages to the Jeen completion-service `messages` wire format."""

    out: List[Dict[str, Any]] = []

    for msg in messages:
        if isinstance(msg, SystemMessage):
            role = "system"
        elif isinstance(msg, HumanMessage):
            role = "user"
        elif isinstance(msg, AIMessage):
            tool_calls = list(getattr(msg, "tool_calls", []) or [])
            for call in tool_calls:
                call_id = str(call.get("id") or f"call_{uuid4().hex[:8]}")
                args = call.get("args") if isinstance(call.get("args"), (dict, list)) else {}
                out.append(
                    {
                        "type": "function_call",
                        "call_id": call_id,
                        "name": str(call.get("name") or ""),
                        "arguments": json.dumps(args, ensure_ascii=False),
                    }
                )
            text = msg.content if isinstance(msg.content, str) else ""
            if text:
                out.append(
                    {
                        "type": "message",
                        "role": "assistant",
                        "content": [{"type": "text", "text": text}],
                    }
                )
            continue
        elif isinstance(msg, ToolMessage):
            out.append(
                {
                    "type": "function_call_output",
                    "call_id": str(getattr(msg, "tool_call_id", "") or ""),
                    "output": msg.content if isinstance(msg.content, str) else json.dumps(msg.content),
                }
            )
            continue
        else:
            role = "user"

        content = msg.content if isinstance(msg.content, str) else json.dumps(msg.content)
        out.append(
            {
                "type": "message",
                "role": role,
                "content": [{"type": "text", "text": content}],
            }
        )

    return out


# Root-level keys completion-service's strict ToolParametersDto accepts.
# Any other root-level JSON-Schema keyword (title, $defs, additionalProperties,
# $schema, examples, ...) must be stripped before send. Inner properties.* values
# are forwarded verbatim — completion-service does not recursively validate them,
# so rich per-property schema (enum, description, default, format, ...) reaches
# the LLM intact. Mirrors agent-service's `McpToolStrategy.convertToCompletionFormat`.
_TOOL_PARAM_ROOT_KEYS = ("type", "properties", "items", "description", "required")


def _shape_tool_parameters(raw: Any) -> Dict[str, Any]:
    """Reshape a JSON-Schema-like object into completion-service's strict root."""
    if not isinstance(raw, dict):
        return {"type": "object"}
    shaped: Dict[str, Any] = {"type": raw.get("type") or "object"}
    if isinstance(raw.get("properties"), dict):
        shaped["properties"] = raw["properties"]
    if isinstance(raw.get("required"), list):
        shaped["required"] = [r for r in raw["required"] if isinstance(r, str)]
    if "items" in raw:
        shaped["items"] = _shape_tool_parameters(raw["items"])
    if isinstance(raw.get("description"), str):
        shaped["description"] = raw["description"]
    return shaped


def _tools_to_jeen(bound_tools: Optional[List[Any]]) -> Optional[List[Dict[str, Any]]]:
    """Convert LangChain Tool-like objects to the Jeen completion-service tool schema."""

    if not bound_tools:
        return None

    converted: List[Dict[str, Any]] = []
    for tool in bound_tools:
        name = getattr(tool, "name", None) or (tool.get("name") if isinstance(tool, dict) else None)
        if not name:
            continue
        description = (
            getattr(tool, "description", None)
            or (tool.get("description") if isinstance(tool, dict) else None)
            or ""
        )

        raw_schema: Dict[str, Any] = {"type": "object"}
        args_schema = getattr(tool, "args_schema", None)
        if args_schema is not None and hasattr(args_schema, "model_json_schema"):
            try:
                raw_schema = args_schema.model_json_schema()
            except Exception:  # noqa: BLE001 - any schema generation failure -> empty object
                raw_schema = {"type": "object"}
        elif args_schema is not None and hasattr(args_schema, "schema"):
            try:
                raw_schema = args_schema.schema()
            except Exception:  # noqa: BLE001
                raw_schema = {"type": "object"}
        elif isinstance(tool, dict) and isinstance(tool.get("parameters"), dict):
            raw_schema = tool["parameters"]

        converted.append(
            {
                "type": "function",
                "name": str(name),
                "description": str(description),  # @IsString() on completion-service requires non-undefined
                "parameters": _shape_tool_parameters(raw_schema),
            }
        )

    return converted or None


def _parse_sse_lines(line_iter) -> List[Dict[str, Any]]:
    """Reassemble SSE `data:` lines into JSON event objects."""

    events: List[Dict[str, Any]] = []
    buffer: List[str] = []
    for raw in line_iter:
        if raw is None:
            continue
        if isinstance(raw, bytes):
            raw = raw.decode("utf-8", errors="replace")
        line = raw.rstrip("\r")
        if line == "":
            if buffer:
                data_payload = "".join(b[5:].strip() if b.startswith("data:") else "" for b in buffer)
                buffer = []
                if not data_payload:
                    continue
                try:
                    events.append(json.loads(data_payload))
                except json.JSONDecodeError:
                    continue
            continue
        buffer.append(line)
    if buffer:
        data_payload = "".join(b[5:].strip() if b.startswith("data:") else "" for b in buffer)
        if data_payload:
            try:
                events.append(json.loads(data_payload))
            except json.JSONDecodeError:
                pass
    return events


class JeenChatModel(BaseChatModel):
    """LangChain chat model that talks to ``llm-core POST /api/v1/completions``."""

    llm_core_url: str
    model_id: str
    access_token: str
    temperature: float = 0.7
    max_output_tokens: Optional[int] = None
    top_p: Optional[float] = None
    system_message: str = ""
    stream_enabled: bool = True
    request_timeout: float = _REQUEST_TIMEOUT_SECONDS
    stream_timeout: float = _STREAM_TIMEOUT_SECONDS
    # Forwarded verbatim under `context` to llm-core (and through to completion-service
    # for FinOps attribution / analytics). The same convention is used by the chat
    # path's ConversationFlowService: context.workflowId / context.workflowName.
    workflow_id: Optional[str] = None
    workflow_name: Optional[str] = None
    extra_context: Optional[Dict[str, Any]] = None
    _bound_tools: Optional[List[Any]] = None

    class Config:
        arbitrary_types_allowed = True

    @property
    def _llm_type(self) -> str:
        return "jeen_language_model"

    def bind_tools(self, tools: List[Any]):
        self._bound_tools = list(tools or [])
        return self

    def _endpoint(self) -> str:
        base = (self.llm_core_url or "").rstrip("/")
        return f"{base}/api/v1/completions"

    def _headers(self) -> Dict[str, str]:
        # _validate_jwt also strips Bearer / surrounding quotes for us.
        token = _validate_jwt(self.access_token)
        return {
            "Authorization": f"Bearer {token}",
            "Content-Type": "application/json",
        }

    def _build_payload(self, messages: Sequence[BaseMessage], stream: bool) -> Dict[str, Any]:
        wire_messages = _convert_messages_to_jeen(messages)
        if self.system_message and not any(
            m.get("type") == "message" and m.get("role") == "system" for m in wire_messages
        ):
            wire_messages.insert(
                0,
                {
                    "type": "message",
                    "role": "system",
                    "content": [{"type": "text", "text": self.system_message}],
                },
            )

        payload: Dict[str, Any] = {
            "model": self.model_id,
            "messages": wire_messages,
            "stream": stream,
        }

        if self.temperature is not None:
            payload["temperature"] = float(self.temperature)
        if self.max_output_tokens:
            payload["maxOutputTokens"] = int(self.max_output_tokens)
        if self.top_p is not None:
            payload["topP"] = float(self.top_p)

        tools = _tools_to_jeen(self._bound_tools)
        if tools:
            payload["tools"] = tools

        context = self._build_context()
        if context:
            payload["context"] = context

        return payload

    def _build_context(self) -> Dict[str, Any]:
        """Assemble the optional ``context`` block forwarded to llm-core.

        FinOps attribution (``workflowId`` / ``workflowName``) is placed under
        ``context.dimensions`` directly — the same shape completion-service's
        ``buildFinOpsDimensions`` consumes, and the same shape the chat path
        (``ConversationExecutorService.buildContext``) produces. llm-core
        forwards the context verbatim (only stamping ``userId`` from the JWT
        and defaulting ``sourceService`` / ``useCase``).

        Caller-supplied ``extra_context`` is merged first; any
        ``extra_context.dimensions`` is shallow-merged with our workflow
        dimensions, with the workflow values taking precedence.
        """
        context: Dict[str, Any] = {}
        extra_dimensions: Dict[str, Any] = {}

        if isinstance(self.extra_context, dict):
            for k, v in self.extra_context.items():
                if v is None:
                    continue
                if k == "dimensions" and isinstance(v, dict):
                    extra_dimensions = dict(v)
                    continue
                context[str(k)] = v

        workflow_dimensions: Dict[str, Any] = {}
        if self.workflow_id:
            workflow_dimensions["workflowId"] = str(self.workflow_id)
        if self.workflow_name:
            workflow_dimensions["workflowName"] = str(self.workflow_name)

        dimensions = {**extra_dimensions, **workflow_dimensions}
        if dimensions:
            context["dimensions"] = dimensions
        return context

    def _generate(
        self,
        messages: List[BaseMessage],
        stop: Optional[List[str]] = None,
        run_manager: Optional[CallbackManagerForLLMRun] = None,
        **kwargs: Any,
    ) -> ChatResult:
        if self.stream_enabled:
            text_parts: List[str] = []
            tool_calls: Dict[str, Dict[str, Any]] = {}
            tool_call_order: List[str] = []
            for chunk in self._stream(messages, stop=stop, run_manager=run_manager, **kwargs):
                content = chunk.message.content
                if isinstance(content, str) and content:
                    text_parts.append(content)
                for call in getattr(chunk.message, "tool_call_chunks", None) or []:
                    call_id = str(call.get("id") or call.get("index") or "")
                    if call_id not in tool_calls:
                        tool_calls[call_id] = {
                            "id": call_id,
                            "name": call.get("name") or "",
                            "args": "",
                        }
                        tool_call_order.append(call_id)
                    if call.get("name"):
                        tool_calls[call_id]["name"] = call["name"]
                    args_delta = call.get("args") or ""
                    if args_delta:
                        tool_calls[call_id]["args"] += args_delta

            text = "".join(text_parts)
            ordered_calls = [tool_calls[cid] for cid in tool_call_order if tool_calls[cid].get("name")]
            message = self._materialize_ai_message(text, ordered_calls)
            return ChatResult(generations=[ChatGeneration(message=message)])

        payload = self._build_payload(messages, stream=False)
        try:
            response = requests.post(
                self._endpoint(),
                json=payload,
                headers=self._headers(),
                timeout=self.request_timeout,
            )
        except requests.RequestException as exc:
            raise RuntimeError(f"Jeen completion request failed: {exc}") from exc

        if response.status_code >= 400:
            raise RuntimeError(self._format_http_error(response.status_code, response.text))

        try:
            body = response.json()
        except ValueError as exc:
            raise RuntimeError(f"Jeen completion returned non-JSON body: {exc}") from exc

        text = body.get("outputText") or ""
        tool_outputs = body.get("output") or []
        tool_calls: List[Dict[str, Any]] = []
        for entry in tool_outputs:
            if entry.get("type") != "function_call":
                continue
            try:
                parsed_args = json.loads(entry.get("arguments") or "{}")
            except json.JSONDecodeError:
                parsed_args = {}
            tool_calls.append(
                {
                    "id": entry.get("callId") or f"call_{uuid4().hex[:8]}",
                    "name": entry.get("name") or "",
                    "args": parsed_args,
                }
            )

        message = self._materialize_ai_message(text, tool_calls)
        return ChatResult(generations=[ChatGeneration(message=message)])

    def _stream(
        self,
        messages: List[BaseMessage],
        stop: Optional[List[str]] = None,
        run_manager: Optional[CallbackManagerForLLMRun] = None,
        **kwargs: Any,
    ):
        payload = self._build_payload(messages, stream=True)
        try:
            response = requests.post(
                self._endpoint(),
                json=payload,
                headers=self._headers(),
                stream=True,
                timeout=self.stream_timeout,
            )
        except requests.RequestException as exc:
            raise RuntimeError(f"Jeen completion stream failed to start: {exc}") from exc

        if response.status_code >= 400:
            body = response.text if hasattr(response, "text") else ""
            raise RuntimeError(self._format_http_error(response.status_code, body))

        events = _parse_sse_lines(response.iter_lines(decode_unicode=True))
        tool_call_index_by_id: Dict[str, int] = {}

        for event in events:
            event_type = event.get("type")
            if event_type in ("text_delta", "text_delta_start"):
                delta = event.get("delta") if event_type == "text_delta" else event.get("text")
                if not delta:
                    continue
                yield ChatGenerationChunk(message=AIMessageChunk(content=delta))
                if run_manager is not None:
                    run_manager.on_llm_new_token(delta)
            elif event_type == "tool_call_start":
                call_id = str(event.get("callId") or "")
                if not call_id:
                    continue
                idx = tool_call_index_by_id.setdefault(call_id, len(tool_call_index_by_id))
                yield ChatGenerationChunk(
                    message=AIMessageChunk(
                        content="",
                        tool_call_chunks=[
                            {
                                "id": call_id,
                                "name": event.get("name") or "",
                                "args": "",
                                "index": idx,
                            }
                        ],
                    )
                )
            elif event_type == "tool_call_delta":
                call_id = str(event.get("callId") or "")
                if not call_id:
                    continue
                idx = tool_call_index_by_id.setdefault(call_id, len(tool_call_index_by_id))
                yield ChatGenerationChunk(
                    message=AIMessageChunk(
                        content="",
                        tool_call_chunks=[
                            {
                                "id": call_id,
                                "name": "",
                                "args": event.get("argumentsDelta") or "",
                                "index": idx,
                            }
                        ],
                    )
                )
            elif event_type == "error":
                raise RuntimeError(f"Jeen completion stream error: {event.get('message') or 'unknown error'}")
            elif event_type == "finish":
                break

    def _format_http_error(self, status: int, body: str) -> str:
        """Build a verbose error string for non-2xx responses from llm-core.

        For 401/403 we additionally decode the JWT (no verification) so the user
        can immediately see whether it is expired, has the wrong audience, etc.,
        rather than chasing a generic ``Invalid or expired token`` from passport.
        """
        snippet = (body or "")[:500].replace("\n", " ")
        msg = f"Jeen completion returned HTTP {status}: {snippet}"
        if status in (401, 403):
            try:
                cleaned = _strip_bearer(self.access_token)
                msg += (
                    f" | JWT diagnostics: {_summarize_jwt(cleaned)}. "
                    "If 'EXPIRED', refresh the token in the Access Token field. "
                    "If 'aud' does not match what llm-core expects, you are using a token "
                    "minted for a different service. If 'not a JWT', the upstream output is "
                    "probably wrapped in JSON - send only the raw token string."
                )
            except Exception:  # noqa: BLE001 - diagnostics must never themselves throw
                pass
        return msg

    def _materialize_ai_message(self, text: str, tool_calls: List[Dict[str, Any]]) -> AIMessage:
        if not tool_calls:
            return AIMessage(content=text or "")

        normalized: List[Dict[str, Any]] = []
        for call in tool_calls:
            args = call.get("args")
            if isinstance(args, str):
                try:
                    args = json.loads(args) if args else {}
                except json.JSONDecodeError:
                    args = {}
            normalized.append(
                {
                    "id": call.get("id") or f"call_{uuid4().hex[:8]}",
                    "name": call.get("name") or "",
                    "args": args if isinstance(args, dict) else {},
                    "type": "tool_call",
                }
            )

        return AIMessage(
            content=text or "",
            tool_calls=normalized,
            additional_kwargs={
                "tool_calls": [
                    {
                        "id": call["id"],
                        "type": "function",
                        "function": {
                            "name": call["name"],
                            "arguments": json.dumps(call["args"], ensure_ascii=False),
                        },
                    }
                    for call in normalized
                ]
            },
        )


class JeenLanguageModelComponent(LCModelComponent):
    """Langflow component exposing Jeen-allowed LLMs as a Language Model."""

    display_name: str = "Jeen Language Model"
    description: str = (
        "Call any Jeen-configured completion model. Exposes a LangChain-compatible Language Model "
        "(usable by Agent, Structured Output, etc.) and Model Response. Invocation requires a valid "
        "user JWT; FinOps attribution (workflowId / workflowName) is added automatically from the "
        "running Langflow graph."
    )
    icon: str = "sparkles"
    name: str = "JeenLanguageModel"

    inputs = [
        *LCModelComponent._base_inputs,
        MessageTextInput(
            name="llm_core_url",
            display_name="Jeen llm-core URL",
            info=(
                "Base URL of the Jeen llm-core service. Used for authenticated completions "
                "(POST /api/v1/completions)."
            ),
            value=_DEFAULT_LLM_CORE_URL,
            real_time_refresh=False,
        ),
        MessageTextInput(
            name="access_token",
            display_name="Access Token (JWT)",
            info=(
                "User JWT used to call Jeen llm-core for completions. Either paste a token directly "
                "or connect a text/Message output from an upstream component (e.g. a JWT extracted "
                "from jeen-attachments). Note: this field is NOT masked because Langflow secret "
                "inputs cannot accept upstream connections."
            ),
