    def update_build_config(
        self,
        build_config: dict,
        field_value: str,
        field_name: str | None = None,
    ) -> dict:
        """Hook called by Langflow's ``/api/v1/custom_component/update`` endpoint.

        We only react to refreshes on the ``model_name`` dropdown.
        Everything else (``llm_core_url``, ``access_token``, etc.) is
        static and handled by the runtime ``build_model`` path.
        """
        try:
            if field_name == "model_name":
                self._refresh_live_models(build_config)
        except Exception as e:  # noqa: BLE001 - never break the editor on a refresh
            self.log(f"[update_build_config] Error: {e}")
        return build_config

    def _refresh_live_models(self, build_config: dict) -> None:
        """Populate the ``model_name`` dropdown with completion models the
        *current user* may invoke.

        Calls user-service's ``GET /api/v1/settings/me`` (the same route
        the playground UI uses for its model dropdowns) — that endpoint
        joins the user's organisation's model selections with the
        sanitised model details from llm-core, so it returns only the
        models the user is actually allowed to call. Compared to
        llm-core's deployment-wide ``/available-models/selections/completion``
        this respects per-org ``isEnabled`` selections and does not
        require admin permissions.

        Backwards-compat: any value already present on the field (e.g. a
        hardcoded ``gpt-5.4-nano`` saved before this picker existed) is
        preserved as an option even if the live list omits it, so old
        flows keep loading without manual intervention.
        """
        if "model_name" not in build_config:
            return

        # Preserve whatever the field is currently set to so a saved flow's
        # legacy hardcoded value isn't silently dropped on refresh.
        existing_value = str(build_config["model_name"].get("value") or "").strip()

        jwt = _get_jeen_jwt()
        if not jwt:
            options = [existing_value] if existing_value else []
            build_config["model_name"]["options"] = options
            build_config["model_name"]["info"] = (
                "Workspace JWT not found. Open this flow from the Jeen "
                "playground (the iframe will inject your session) and "
                "click refresh again."
            )
            return

        user_service_url = _DEFAULT_USER_SERVICE_URL

        try:
            resp = requests.get(
                f"{user_service_url.rstrip('/')}/api/v1/settings/me",
                headers={
                    "Authorization": f"Bearer {jwt}",
                    "Content-Type": "application/json",
                },
                timeout=_AVAILABLE_MODELS_TIMEOUT_SECONDS,
            )
        except Exception as e:  # noqa: BLE001
            options = [existing_value] if existing_value else []
            build_config["model_name"]["options"] = options
            build_config["model_name"]["info"] = (
                f"Network error contacting user-service ({user_service_url}): {e}"
            )
            return

        if resp.status_code != 200:
            options = [existing_value] if existing_value else []
            build_config["model_name"]["options"] = options
            build_config["model_name"]["info"] = (
                f"user-service returned HTTP {resp.status_code}. "
                "Your session may have expired — reload the workspace."
            )
            return

        try:
            body = resp.json()
        except ValueError:
            body = {}
        # user-service wraps responses as {status, timestamp, data: {...}}
        # via its global response interceptor.
        payload = body.get("data") if isinstance(body, dict) else None
        if not isinstance(payload, dict):
            payload = body if isinstance(body, dict) else {}

        available = payload.get("availableModels") or {}
        details = available.get("details") if isinstance(available, dict) else None
        selections = available.get("selections") if isinstance(available, dict) else None
        if not isinstance(details, list):
            details = []

        # selections list tells us which availableModelId is enabled for the org.
        # When present, only show enabled rows. When absent (older shapes),
        # fall back to the model row's own isEnabled flag.
        enabled_ids: Optional[set] = None
        if isinstance(selections, list):
            enabled_ids = {
                str(s.get("availableModelId"))
                for s in selections
                if isinstance(s, dict) and s.get("isEnabled") and s.get("availableModelId")
            }

        # The runtime resolver in llm-core treats a non-UUID `model` field
        # as an already-resolved provider model name. So we populate the
        # dropdown with `model.name` slugs (e.g. 'gpt-5.4-nano') — bit-for-bit
        # the same string flow authors used to type by hand.
        options: List[str] = []
        seen: set = set()
        skipped_no_name = 0
        for item in details:
            if not isinstance(item, dict):
                continue
            model_obj = item.get("model") if isinstance(item.get("model"), dict) else {}
            if str(model_obj.get("type") or "").lower() != "completion":
                continue
            am_id = str(item.get("id") or "")
            if enabled_ids is not None and am_id not in enabled_ids:
                continue
            if enabled_ids is None and item.get("isEnabled") is False:
                continue
            identifier = (model_obj.get("name") or "").strip()
            if not identifier:
                skipped_no_name += 1
                continue
            if identifier in seen:
                continue
            seen.add(identifier)
            options.append(identifier)

        options.sort()

        # Preserve a saved hardcoded value if the live list doesn't include it,
        # so legacy flows still load with their original model selected.
        if existing_value and existing_value not in seen:
            options.insert(0, existing_value)

        build_config["model_name"]["options"] = options
        if options:
            live_count = len(seen)
            info = f"Loaded {live_count} completion model(s) available to you."
            if existing_value and existing_value not in seen:
                info += f" Saved value '{existing_value}' is not in the live list — kept for compatibility."
            if skipped_no_name:
                info += f" ({skipped_no_name} hidden — missing model.name in payload.)"
        elif skipped_no_name:
            info = (
                f"Found {skipped_no_name} completion model(s) but none expose a "
                "`model.name` slug — check user-service /settings/me payload."
            )
        else:
            info = "No completion models enabled for your organisation."
        build_config["model_name"]["info"] = info

    def _resolve_text_input(self, field_name: str) -> str:
        """Read a text-typed input, normalising the shapes Langflow may deliver.

        ``MessageTextInput`` values arrive as plain strings when the user types
        directly, but as ``Message`` objects (with ``get_text`` / ``.text``),
        ``SecretStr``, or serialised dicts (``{"text": ...}`` / ``{"value": ...}``)
        when wired from an upstream component. Centralising the unwrap here keeps
        every field reader consistent.
        """
        value = getattr(self, field_name, None)
        if value is None:
            return ""
        if hasattr(value, "get_secret_value"):
            try:
                return str(value.get_secret_value() or "").strip()
            except Exception:  # noqa: BLE001
                return ""
        if hasattr(value, "get_text"):
            try:
                return str(value.get_text() or "").strip()
            except Exception:  # noqa: BLE001
                return ""
        if hasattr(value, "text"):
            text_attr = getattr(value, "text", None)
            if text_attr:
                return str(text_attr).strip()
        if isinstance(value, dict):
            inner = value.get("text") or value.get("value")
            return str(inner or "").strip()
        return str(value).strip()

    def _resolve_model_id(self) -> str:
        """Return the canonical model name selected by the flow author.

        Sourced from the ``model_name`` dropdown, which is populated at
        build-time from user-service's ``/settings/me`` and stores the
        provider model slug verbatim (e.g. ``gpt-5.4-nano``). The string
        is forwarded as-is through llm-core to completion-service, which
        validates it against its configured provider catalog. Pre-existing
        flows with a hardcoded string saved into this field still resolve
        identically.
        """
        value = self._resolve_text_input("model_name")
        if not value:
            raise ValueError(
                "Jeen Language Model: Model is required. Click the refresh icon on the "
                "Model field to load the models available for your organisation, then "
                "select one."
            )
        return value

    def build_model(self) -> LanguageModel:  # type: ignore[type-var]
        llm_core_url = self._resolve_text_input("llm_core_url") or _DEFAULT_LLM_CORE_URL
        access_token = self._resolve_text_input("access_token")
        temperature = float(getattr(self, "temperature", 0.7) or 0.7)
        max_output_tokens_raw = getattr(self, "max_output_tokens", 0) or 0
        try:
            max_output_tokens = int(max_output_tokens_raw)
        except (TypeError, ValueError):
            max_output_tokens = 0
        top_p_raw = getattr(self, "top_p", 1.0)
        try:
            top_p = float(top_p_raw) if top_p_raw is not None else None
        except (TypeError, ValueError):
            top_p = None
        system_message = getattr(self, "system_message", "") or ""
        stream_enabled = bool(getattr(self, "stream", True))

        workflow_id, workflow_name = self._resolve_workflow_context()
        extra_context = self._parse_extra_context(getattr(self, "extra_context_json", None))

        try:
            access_token = _validate_jwt(str(access_token))
        except JeenJwtError as exc:
            raise ValueError(f"Jeen Language Model: {exc}") from exc

        model_id = self._resolve_model_id()

        return JeenChatModel(
            llm_core_url=llm_core_url,
            model_id=model_id,
            access_token=str(access_token),
            temperature=temperature,
            max_output_tokens=max_output_tokens or None,
            top_p=top_p,
            system_message=system_message,
            stream_enabled=stream_enabled,
            workflow_id=workflow_id,
            workflow_name=workflow_name,
            extra_context=extra_context,
        )

    def _resolve_workflow_context(self) -> tuple[Optional[str], Optional[str]]:
        """Read workflowId / workflowName from the running Langflow graph.

        Verified against Langflow v1.9.2 (`src/lfx/.../graph/graph/base.py` and
        `src/lfx/.../custom/custom_component/custom_component.py`): every Component
        instance is attached to a Vertex whose `.graph` carries `flow_id` and
        `flow_name`. The public `self.graph` property is `self._vertex.graph`,
        so the safest path is to read through the vertex defensively — that way
        component instantiations outside a running graph (tests, schema
        generation, etc.) do not raise `AttributeError`.

        `flow_name` is populated by the standard `POST /v1/run/{flow_id}` path
        (via `flow.name` on the DB record). The advanced/experimental run path
        omits it, in which case we transparently send only `workflowId`.
        """
        vertex = getattr(self, "_vertex", None)
        graph = getattr(vertex, "graph", None) if vertex is not None else None
        if graph is None:
            return None, None
        raw_id = getattr(graph, "flow_id", None)
        raw_name = getattr(graph, "flow_name", None)
        flow_id = str(raw_id).strip() if raw_id else None
        flow_name = str(raw_name).strip() if raw_name else None
        return (flow_id or None), (flow_name or None)

    @staticmethod
    def _parse_extra_context(raw: Any) -> Optional[Dict[str, Any]]:
        """Parse the optional JSON blob from `extra_context_json`. Returns None if
        empty or invalid. Invalid JSON is surfaced loudly so users don't silently
        drop tracing data they expected to forward."""
        if raw is None:
            return None
        if isinstance(raw, dict):
            return raw
        text = str(raw).strip()
        if not text:
            return None
        try:
            parsed = json.loads(text)
        except json.JSONDecodeError as exc:
            raise ValueError(
                f"Jeen Language Model: Extra Context (JSON) is not valid JSON: {exc.msg} "
                f"at line {exc.lineno} col {exc.colno}"
            ) from exc
        if not isinstance(parsed, dict):
            raise ValueError(
                "Jeen Language Model: Extra Context (JSON) must be a JSON object "
                f"(got {type(parsed).__name__})."
            )
        return parsed

import json
from langflow.custom import Component
from langflow.io import MessageInput, Output
from langflow.schema import Data

class ExtractJWTComponent(Component):
    display_name = "Parse Nested Message"
    description = "Robustly extracts JSON data even if wrapped in weird string formatting."
    icon = "braces"

    inputs = [
        MessageInput(
            name="input_message",
            display_name="Input Message",
            info="Connect the node outputting your Message here.",
            required=True,
        ),
    ]

    outputs = [
        Output(
            display_name="Parsed Data",
            name="parsed_data",
            method="parse_message",
        ),
    ]

    def parse_message(self) -> Data:
        try:
            # 1. Safely extract text from the Langflow Message object
            raw_text = self.input_message.text if hasattr(self.input_message, 'text') else str(self.input_message)
            raw_text = raw_text.strip()
            
            # 2. Fix: If the string starts explicitly with "message": but lacks outer braces, wrap it.
            if raw_text.startswith('"message":'):
                raw_text = "{" + raw_text + "}"

            parsed_data = None

            # 3. Attempt standard JSON parsing first
            try:
                parsed_data = json.loads(raw_text)
            except json.JSONDecodeError:
                # 4. Failsafe: Extract only the substring between the first { and last }
                start = raw_text.find('{')
                end = raw_text.rfind('}')
                
                if start != -1 and end != -1:
                    clean_text = raw_text[start:end+1]
                    parsed_data = json.loads(clean_text)
                else:
                    raise ValueError("No JSON object could be found in the text.")

            # 5. Unwrap the nested stringified JSON if it exists
            if isinstance(parsed_data, dict) and "message" in parsed_data:
                inner_content = parsed_data["message"]
                
                if isinstance(inner_content, str):
                    try:
                        # Parse the inner string (this contains your JWT)
                        parsed_data = json.loads(inner_content)
                    except json.JSONDecodeError:
                        # Final Failsafe: extract substring from the inner string
                        start = inner_content.find('{')
                        end = inner_content.rfind('}')
                        if start != -1 and end != -1:
                            parsed_data = json.loads(inner_content[start:end+1])

            self.status = "Successfully extracted JWT data."
            
            # Return the clean dictionary so your `{jwt}` template works
            return Data(data=parsed_data)
            
        except Exception as e:
            # Update the UI status with the exact error
            self.status = f"Parsing Error: {str(e)}"
            return Data(data={"error": str(e)})
